SELECT *
FROM proprietary_fund_versions
WHERE version_status = 'final';

SELECT SUM(fund_balance) AS total_fund_balance
FROM proprietary_funds
WHERE is_active = 1;

SELECT COUNT(*) AS draft_version_count
FROM financial_statement_versions
WHERE version_status = 'draft';

SELECT version_status
FROM financial_statement_versions
WHERE created_by = 'John Doe' AND version_status = 'draft';

SELECT fund_balance, revenues, expenditures
FROM governmental_funds
WHERE entity_id = 1 AND fund_type = 'general' AND is_active = 1;
